{"output": "def get_page(
        self,
        url: str,
        wait_time: int = 2000,
        wait_until: str = "networkidle"
    ) -> PageResult:
        """
        获取单个页面

        Args:
            url: 目标URL
            wait_time: 等待JS渲染时间（毫秒）
            wait_until: 等待条件 ('load', 'domcontentloaded', 'networkidle')

        Returns:
            PageResult对象
        """
        if not self._page:
            raise RuntimeError("浏览器未启动，请先调用 launch()")

        for attempt in range(self.retry):
            try:
                response = self._page.goto(url, timeout=self.timeout, wait_until=wait_until)

                if wait_time > 0:
                    self._page.wait_for_timeout(wait_time)

                cookies = {}
                for cookie in self._context.cookies():
                    cookies[cookie['name']] = cookie['value']

                return PageResult(
                    url=self._page.url,
                    status=response.status if response else 0,
                    title=self._page.title(),
                    text=self._extract_text(self._page, self._page.content()),
                    html=self._page.content(),
                    cookies=cookies
                )

            except Exception as e:
                if attempt == self.retry - 1:
                    return PageResult(
                        url=url,
                        status=0,
                        error=f"获取失败: {str(e)}"
                    )
                time.sleep(self.anti_detection.get_random_delay())

        return PageResult(url=url, status=0, error="重试次数耗尽")", "exit_code": 0, "error": null}
